var resp = $.steps.fetchEmails.response || {};
var messages = resp.messages || [];
var emailList = messages.slice(0, 15).map(function(m, i) {
  var id = m.id || '';
  var threadId = m.threadId || '';
  var snippet = m.snippet || '';
  var subject = '';
  var from = '';
  var date = '';
  if (m.payload && m.payload.headers) {
    m.payload.headers.forEach(function(h) {
      if (h.name === 'Subject') subject = h.value || '';
      if (h.name === 'From') from = h.value || '';
      if (h.name === 'Date') date = h.value || '';
    });
  }
  return { index: i + 1, id: id, subject: subject || snippet.slice(0, 60), from: from, date: date, snippet: snippet.slice(0, 200) };
});
var emailSummary = emailList.map(function(e) {
  return e.index + '. Subject: ' + e.subject + '\n   From: ' + e.from + '\n   Date: ' + e.date + '\n   Preview: ' + e.snippet;
}).join('\n\n');
return { emailList: emailList, emailSummary: emailSummary, count: emailList.length };

var ctx = $.steps.extractEmails.output;
var prompt = 'You are an intelligent email organizer. Categorize the following emails into smart labels and provide a prioritized digest.

EMAILS (' + ctx.count + ' total):
' + ctx.emailSummary + '

Categorize each email with one of these labels:
- URGENT: Requires immediate attention
- ACTION_REQUIRED: Needs a response or action within 24h
- FOLLOW_UP: Something to follow up on later
- FYI: Informational, no action needed
- NEWSLETTER: Marketing or subscription content
- SPAM_SUSPECT: Likely spam or unwanted

Return ONLY valid JSON:
{
  "digest": "Brief overall summary of inbox state",
  "urgentCount": 0,
  "actionCount": 0,
  "emails": [
    { "index": 1, "subject": "...", "from": "...", "label": "URGENT", "reason": "...", "suggestedAction": "..." }
  ]
}';
return { prompt };

let raw = $.steps.aiCategorize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':email: Email Digest - ' + new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' }), emoji: true } });
if (ai.digest) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.digest } });
}
var urgentCount = ai.urgentCount || 0;
var actionCount = ai.actionCount || 0;
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':rotating_light: *Urgent:* ' + urgentCount + '  |  :point_right: *Action Required:* ' + actionCount + '  |  :incoming_envelope: *Total:* ' + $.steps.extractEmails.output.count } });
blocks.push({ type: 'divider' });
var labelEmojis = { URGENT: ':rotating_light:', ACTION_REQUIRED: ':point_right:', FOLLOW_UP: ':clock3:', FYI: ':information_source:', NEWSLETTER: ':newspaper:', SPAM_SUSPECT: ':wastebasket:' };
var emails = ai.emails || [];
var grouped = {};
emails.forEach(function(e) {
  var label = e.label || 'FYI';
  if (!grouped[label]) grouped[label] = [];
  grouped[label].push(e);
});
var labelOrder = ['URGENT', 'ACTION_REQUIRED', 'FOLLOW_UP', 'FYI', 'NEWSLETTER', 'SPAM_SUSPECT'];
labelOrder.forEach(function(label) {
  var items = grouped[label];
  if (!items) return;
  var emoji = labelEmojis[label] || ':email:';
  var sectionText = emoji + ' *' + label.replace(/_/g, ' ') + '* (' + items.length + ')\n';
  items.forEach(function(e) {
    sectionText += '  - *' + (e.subject || 'No subject') + '* from ' + (e.from || 'Unknown') + '\n';
    if (e.suggestedAction) sectionText += '    _Action: ' + e.suggestedAction + '_\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sectionText } });
});
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':robot_face: Organized by Claude AI via One CLI' }] });
var fallback = 'Email Digest: ' + urgentCount + ' urgent, ' + actionCount + ' action required, ' + emails.length + ' total';
if (ai.text) fallback = ai.text.slice(0, 500);
return { blocks, fallback };
